package Temas;

public class Ejemplo {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		System.out.println(7+2);
		
		System.out.println(7+2 + "es el resultado");
		System.out.println("Operacion " + 7+2 + " es el resultado");
		System.out.println("Operacion" + 7-2 + " es el resultado"); //da error porque java no ve el menos como un operador
		System.out.println("Operacion" + 7*2 + " es el resultado");
		System.out.println("Operacion" + (7-2) + " es el resultado");
	}

}
